package com.fanmes.common.security;
import com.fasterxml.jackson.databind.ObjectMapper; import com.fanmes.common.api.ApiResponse; import jakarta.servlet.*; import jakarta.servlet.http.*; import java.io.IOException; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.MediaType; import org.springframework.stereotype.Component; import org.springframework.web.filter.OncePerRequestFilter;
@Component public class JwtAuthenticationFilter extends OncePerRequestFilter { public static final String AUTHENTICATED_USER_ATTRIBUTE=JwtAuthenticationFilter.class.getName()+".user"; private final JwtTokenService tokens; private final ObjectMapper mapper; private final boolean enabled; public JwtAuthenticationFilter(JwtTokenService tokens,ObjectMapper mapper,@Value("${fanmes.security.auth-enabled:true}") boolean enabled){this.tokens=tokens;this.mapper=mapper;this.enabled=enabled;} protected boolean shouldNotFilter(HttpServletRequest r){return !enabled||"OPTIONS".equalsIgnoreCase(r.getMethod())||r.getRequestURI().contains("/health")||"/api/auth/login".equals(r.getRequestURI());} protected void doFilterInternal(HttpServletRequest r,HttpServletResponse p,FilterChain c)throws ServletException,IOException{try{r.setAttribute(AUTHENTICATED_USER_ATTRIBUTE,tokens.verify(r.getHeader("Authorization")));c.doFilter(r,p);}catch(RuntimeException e){p.setStatus(401);p.setContentType(MediaType.APPLICATION_JSON_VALUE);p.setCharacterEncoding("UTF-8");mapper.writeValue(p.getWriter(),ApiResponse.error(401,e.getMessage()));}} }
